+
+func TestAddClassAfterTfIdf(t *testing.T) {
+	c := NewClassifierTfIdf(Good, Bad)
+	c.Learn([]string{"hello", "world"}, Good)
+	c.Learn([]string{"goodbye", "world"}, Bad)
+	c.ConvertTermsFreqToTfIdf()
+
+	// Try to add class after TF-IDF conversion
